91	export const MAGIC_POT_ANIMATION = {
92	    IDLE: { name: "Idle", trackIdx: 0, loop: true } as MagicPotAnim,
93	    HIT: { name: "Hit", trackIdx: 1, loop: false } as MagicPotAnim,
94	
95	    // 升級到下一階：回傳 [Idle, LVUPXtoY] 的組合
