140	@ccclass('MagicPotController')
141	export class MagicPotController extends Component {
142	    //#region Constants
143	    /**@ch 需要註冊的事件列表 */
144	    private static readonly EVENTS_TO_REGISTER = [
145	        MAGIC_POT_EVENT.INIT,
146	        MAGIC_POT_EVENT.SET_LEVEL,
147	        MAGIC_POT_EVENT.GET_LEVEL,
148	        MAGIC_POT_EVENT.PLAY_COLLECT_EFFECT,
149	        MAGIC_POT_EVENT.PLAY_UPGRADE_EFFECT,
150	        MAGIC_POT_EVENT.SWITCH_UI,
151	        MAGIC_POT_EVENT.PLAY_TO_FREE_GAME,
152	        MAGIC_POT_EVENT.GET_NODE,
153	        MAGIC_POT_EVENT.PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE,
154	        MAGIC_POT_EVENT.POP_TO_FREE_GAME_NUMBER_ROOT_NODE,
155	        Game_Define.EVENT.DEVICE_ROTATION,
156	    ];
157	
158	    /**@ch 魔法罐最高等級（Bingo 等級，client 端 0~3 的最高值）*/
159	    static readonly BINGO_LEVEL: number = 3;
160	
161	    /**@ch 收集效果動畫總時長(秒)*/
162	    private static readonly COLLECT_DURATION: number = 0.5;
163	
164	    /**@ch 收集等待動畫時長(秒)也是間隔時長*/
165	    private static readonly COLLECT_WAIT_DURATION: number = 0.5;
166	    //#endregion Constants
167	
168	    //#region Properties
169	    @property( {
170	        type: Node,
171	        tooltip: "魔法罐"
172	    } )
173	    m_magicPot: Node = null;
174	
175	    /**@ch 收集效果 Prefab*/
176	    @property( {
177	        type: Prefab,
178	        tooltip: "收集效果 Prefab"
179	    } )
180	    m_collectEffect: Prefab = null;
181	
182	    @property( {
183	        type: Node,
184	        tooltip: "飛行目標節點"
185	    } )
186	    m_flyTargetNode: Node = null;
187	
188	    /**@ch 直版魔法罐*/
189	    @property( {
190	        type: Node,
191	        tooltip: "魔法罐（直版）"
192	    } )
193	    m_magicPotPortrait: Node = null;
194	
195	    /**@ch 免費遊戲回合數字掛載根節點*/
196	    @property( {
197	        type: [Node],
198	        tooltip: "免費遊戲回合數字掛載根節點"
199	    } )
200	    m_freeGameNumberRootNodes: Node[] = [];
201	
202	    /**@ch 免費遊戲Spin文字節點*/
203	    @property( {
204	        type: [Node],
205	        tooltip: "免費遊戲Spin文字節點"
206	    } )
207	    m_freeSpinTextNodes : Node[] = [];
208	    //#endregion Properties
209	
210	    //#region Properties
211	    /**@ch 等級（client 顯示等級，0~BINGO_LEVEL=3）*/
212	    private m_level: number;
213	
214	    /**@ch 最近一次 server 等級（0~6），供 GetLevel() 對外回傳維持原契約；m_level 為其映射結果 */
215	    private m_serverLevel: number = 0;
216	
