218	    private m_isInit: boolean;
219	
220	    /**@ch 收集效果實例節點陣列*/
221	    private m_collectEffectNodes: Node[] = [];
222	
223	    /**@ch 當前動畫 Tween 陣列*/
224	    private m_currentTweens: Tween<any>[] = [];
225	
226	    /**@ch 遊戲視圖*/
227	    private m_gameView: GameView = null;
228	
229	    /**@ch 是否註冊事件*/
230	    private m_isEventRegistered: boolean = false;
231	
232	    /**@ch 魔法罐Spine（橫版）*/
233	    private m_magicPotSpine : sp.Skeleton = null;
234	
235	    /**@ch 魔法罐Spine（直版）*/
236	    private m_magicPotPortraitSpine : sp.Skeleton = null;
237	
238	    /**@ch 當前是否為橫版*/
239	    private m_isLandscape: boolean = true;
240	
241	    /**@ch 取得目前顯示中的 Spine */
242	    private get ActiveSpine(): sp.Skeleton {
243	        return this.m_isLandscape ? this.m_magicPotSpine : this.m_magicPotPortraitSpine;
244	    }
245	
246	    /**@ch 免費遊戲回合數字節點*/
247	    private m_freeGameRoundNumberNode: Node = null;
248	
249	    /**@ch 免費遊戲回合數字節點的 Push 資料（用於 PopNode 還原）*/
250	    private m_freeGameRoundNumberPopupData: PopupNodeData = null;
251	    //#endregion Properties
252	
253	    //#region Methods
254	    /**
255	     * @ch 檢查節點或組件是否有效
256	     * @param obj 要檢查的物件
257	     * @param objName 物件名稱（用於錯誤訊息）
258	     * @returns 是否有效
259	     */
260	    private IsValid<T>( obj: T, objName: string ): obj is NonNullable<T>
261	    {
262	        if (!obj) {
263	            log(`[MagicPotController] ${objName} is null or undefined`);
264	            return false;
265	        }
266	        return true;
267	    }
268	
269	    onLoad()
270	    {
271	        this.RegisterEvent();
272	        this.RegisterTestKeyCodes();
273	
274	        if (!this.IsValid(this.m_magicPot, 'm_magicPot')) {
275	            return;
276	        }
277	
278	        this.m_magicPotSpine = this.m_magicPot.getComponent(sp.Skeleton);
279	        if (!this.IsValid(this.m_magicPotSpine, 'm_magicPotSpine')) {
280	            log('[MagicPotController] Failed to get Skeleton component from m_magicPot');
281	        }
282	
283	        if (this.m_magicPotPortrait) {
284	            this.m_magicPotPortraitSpine = this.m_magicPotPortrait.getComponent(sp.Skeleton);
285	            if (!this.IsValid(this.m_magicPotPortraitSpine, 'm_magicPotPortraitSpine')) {
286	                log('[MagicPotController] Failed to get Skeleton component from m_magicPotPortrait');
287	            }
288	        }
289	
290	        // 依初始螢幕方向設定顯示
291	        const windowSize = screen.windowSize;
292	        this.m_isLandscape = windowSize.width >= windowSize.height;
293	        this.m_magicPot.active = this.m_isLandscape;
294	        if (this.m_magicPotPortrait) {
295	            this.m_magicPotPortrait.active = !this.m_isLandscape;
296	        }
297	    }
298	
299	    onDestroy()
300	    {
301	        this.UnregisterEvent();
302	        this.UnregisterTestKeyCodes();
303	
304	        // 停止所有動畫並移除旋轉監聽
305	        this.StopAllAnimations();
306	    }
307	
308	    /**
309	     * @ch 註冊事件
310	     */
311	    private RegisterEvent() {
312	        if (this.m_isEventRegistered) return;
313	
314	        MagicPotController.EVENTS_TO_REGISTER.forEach(eventName => {
315	            eventManager.Register(eventName, this);
316	        });
317	
318	        this.m_isEventRegistered = true;
319	    }
320	
321	    /**
322	     * @ch 取消註冊事件
323	     */
324	    private UnregisterEvent() {
325	        if (!this.m_isEventRegistered) return;
326	
327	        MagicPotController.EVENTS_TO_REGISTER.forEach(eventName => {
328	            eventManager.UnRegister(eventName, this);
329	        });
330	
331	        this.m_isEventRegistered = false;
332	    }
333	
334	    /**
335	     * @ch 事件
336	     * @param event 事件
337	     * @param args 參數
338	     */
339	    OnEvent( event: string, ...args: any[] )
340	    {
341	        switch (event) {
342	            /**@ch 初始化*/
343	            case MAGIC_POT_EVENT.INIT:
344	                if (!this.ValidateInitParams(args)) {
345	                    log('[MagicPotController] INIT event requires: (gameView: GameView, level: number)');
346	                    return;
347	                }
348	                this.Init(args[0], args[1]);
349	                break;
350	
351	            /**@ch 設置等級*/
352	            case MAGIC_POT_EVENT.SET_LEVEL:
353	                if (!this.ValidateLevelParam(args)) {
354	                    log('[MagicPotController] SET_LEVEL event requires: (level: number)');
355	                    return;
356	                }
357	                this.SetLevel(args[0]);
358	                break;
359	
360	            /**@ch 獲取等級*/
361	            case MAGIC_POT_EVENT.GET_LEVEL:
362	                if (!this.ValidateCallbackParam(args)) {
363	                    log('[MagicPotController] GET_LEVEL event requires: (callback: (level: number) => void)');
364	                    return;
365	                }
366	                this.InvokeSafeCallbackWithParam<number>(args[0], this.GetLevel(), "GET_LEVEL");
367	                break;
368	
369	            /**@ch 播放收集效果*/
370	            case MAGIC_POT_EVENT.PLAY_COLLECT_EFFECT:
371	                if (!this.ValidateCollectEffectParams(args)) {
372	                    log('[MagicPotController] PLAY_COLLECT_EFFECT event requires: (platePositions: number[], data: IEnergyLevelUpgradeInfo[], callback?: () => void, isPlayCollectEffect?: boolean, suppressCollectSfx?: boolean)');
373	                    return;
374	                }
375	                this.PlayCollectEffect(args[0], args[1], args[2], args[3], args[4]);
376	                break;
377	
378	            /**@ch 播放升級效果*/
379	            case MAGIC_POT_EVENT.PLAY_UPGRADE_EFFECT:
380	                if (!this.ValidateUpgradeEffectParams(args)) {
381	                    log('[MagicPotController] PLAY_UPGRADE_EFFECT event requires: (data: IEnergyLevelUpgradeInfo, callback?: () => void)');
382	                    return;
383	                }
384	                this.PlayUpgradeEffect(args[0], args[1]);
385	                break;
386	
387	            /**@ch 切換UI*/
388	            case MAGIC_POT_EVENT.SWITCH_UI:
389	                if (!this.ValidateSwitchUIParams(args)) {
390	                    log('[MagicPotController] SWITCH_UI event requires: (isFreeGame: boolean, callback?: () => void)');
391	                    return;
392	                }
393	                this.SwitchUI(args[0], args[1]);
394	                break;
395	
396	            /**@ch 播放進入free game動畫*/
397	            case MAGIC_POT_EVENT.PLAY_TO_FREE_GAME:
398	                if (!this.ValidateSimpleCallbackParam(args)) {
399	                    log('[MagicPotController] PLAY_TO_FREE_GAME event requires: (callback?: () => void)');
400	                    return;
401	                }
402	                this.PlayToFreeGame(args[0]);
403	                break;
404	
405	            /**@ch 獲取節點*/
406	            case MAGIC_POT_EVENT.GET_NODE:
407	                if (!this.ValidateNodeCallbackParam(args)) {
408	                    log('[MagicPotController] GET_NODE event requires: (callback?: (node: Node) => void)');
409	                    return;
410	                }
411	                this.InvokeSafeCallbackWithParam<Node>(args[0], this.node, "GET_NODE");
412	                break;
413	
414	            /**@ch 推入免費遊戲回合數字節點*/
415	            case MAGIC_POT_EVENT.PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE:
416	                this.PushToFreeGameNumberRootNode();
417	                break;
