529	     */
530	    private OnDeviceRotation(): void {
531	        const windowSize = screen.windowSize;
532	        const newIsLandscape = windowSize.width >= windowSize.height;
533	        if (newIsLandscape === this.m_isLandscape) return;
534	
535	        this.m_isLandscape = newIsLandscape;
536	        this.m_magicPot.active = this.m_isLandscape;
537	        if (this.m_magicPotPortrait) {
538	            this.m_magicPotPortrait.active = !this.m_isLandscape;
539	        }
540	
541	        if (!this.m_isInit) return;
542	
543	        // 若回合數字節點已掛載到 RootNode 上，改掛到新方向的 RootNode
544	        if (this.m_freeGameRoundNumberPopupData && this.m_freeGameRoundNumberNode) {
545	            const newRootNode = this.m_isLandscape
546	                ? this.m_freeGameNumberRootNodes[0]
547	                : this.m_freeGameNumberRootNodes[1];
548	            if (newRootNode) {
