575	    /**
576	     * @ch 將 server 端等級（0~6）映射為 client 端顯示等級（0~3）
577	     * 對照：0,1→0｜2,3→1｜4,5→2｜6→3
578	     * ⚠️ 非冪等：對 client 值再呼叫會得到 0,0,1,1，僅允許在 server 值進入時呼叫
579	     * @param serverLevel server 端能量等級
580	     * @returns client 端顯示等級（0~BINGO_LEVEL）
581	     */
582	    private static ConvertServerLevelToClient(serverLevel: number): number {
583	        if (serverLevel >= 6) return MagicPotController.BINGO_LEVEL;
584	        return Math.max(0, Math.floor(serverLevel / 2));
585	    }
