624	    /**
625	     * @ch 播放收集效果
626	     * @param platePositions 盤面位置陣列
627	     * @param data 資料陣列
628	     * @param callback 完成回調（所有效果完成後執行）
629	     * @param isPlayCollectEffect 是否播放收集效果
630	     * @param suppressCollectSfx 是否靜音 MagicPotCollect 音效（FlyToMagicPot 不受此影響；預設 false）
631	     */
632	    async PlayCollectEffect(platePositions: number[], data: IEnergyLevelUpgradeInfo[], callback?: () => void, isPlayCollectEffect: boolean = true, suppressCollectSfx: boolean = false): Promise<void>
633	    {
634	        try {
635	            if (!this.m_isInit || !platePositions || platePositions.length === 0) {
636	                log("PlayCollectEffect 失敗: 未初始化或位置陣列無效");
637	                return;
638	            }
639	
640	            if (!data || data.length === 0) {
641	                log("PlayCollectEffect 失敗: 資料為空");
642	                return;
643	            }
644	
645	            // 停止所有進行中的動畫
646	            this.StopAllAnimations();
647	
648	            const isPlaySequentially = platePositions.length < Game_Define.MAX_SCATTER;
649	            let isPlayUpgradeEffectFinish = !data || data.length === 0;
650	
651	            // 判斷是否有升級資料並決定插入位置（隨機）
652	            const hasUpgrade = data && data.length === 1;
653	            let upgradeInsertIndex = -1;
654	            if (hasUpgrade) {
655	                if (platePositions.length === 1) {
656	                    // 只有一個位置，直接使用索引 0
657	                    upgradeInsertIndex = 0;
658	                } else {
659	                    // 建立索引陣列並打亂，取第一個作為隨機索引
660	                    const indexArray = Array.from({ length: platePositions.length }, (_, i) => i);
661	                    const shuffledArray = tools.GetRandomArrayBySeed(indexArray);
662	                    upgradeInsertIndex = shuffledArray[0];
663	                }
664	            }
665	
666	            if (isPlayCollectEffect) {
667	                if (isPlaySequentially) {
668	                    // 依序播放每個位置的收集效果
669	                    for (let i = 0; i < platePositions.length; i++) {
670	                        const pos = platePositions[i];
671	                        const startNode = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos);
672	                        // 播放飛到魔法罐音效
673	                        AudioManager.Play(AudioManager.AudioClips.FlyToMagicPot);
674	                        await this.PlayCollectEffectByNode(startNode);
675	
676	                        // 播放收集動畫組合：Idle + Hit + LV?
677	                        const collectAnimConfigs = MAGIC_POT_ANIMATION.COLLECT_EFFECT(this.m_level);
678	                        this.PlayMagicPotAnimations(collectAnimConfigs);
679	                        // 播放收集音效（suppressCollectSfx=true 時靜音）
680	                        if (!suppressCollectSfx) {
681	                            AudioManager.Play(AudioManager.AudioClips.MagicPotCollect);
682	                        }
683	                        await Define.Wait(this, MagicPotController.COLLECT_WAIT_DURATION);
684	
685	                        // 如果當前位置是隨機選中的插入點，立即播放升級效果
686	                        if (i === upgradeInsertIndex && !isPlayUpgradeEffectFinish) {
687	                            // log("PlayCollectEffect 播放升級效果，位置: " + pos + "局號:" + commonGameManager.RoundIndex);
688	                            await this.PlayUpgradeEffect(data[0]);
689	                            isPlayUpgradeEffectFinish = true;
690	                        }
691	                    }
692	                } else {
693	                    // 一起播放所有位置的收集效果
694	                    const promises = platePositions.map(pos => {
695	                        const startNode = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos);
696	                        return this.PlayCollectEffectByNode(startNode);
697	                    });
698	
699	                    // 播放飛到魔法罐音效
700	                    AudioManager.Play(AudioManager.AudioClips.FlyToMagicPot);
701	
702	                    // 等待所有動畫完成
703	                    await Promise.all(promises);
704	
705	                    // 播放收集動畫組合：Idle + Hit + LV?
706	                    const collectAnimConfigs = MAGIC_POT_ANIMATION.COLLECT_EFFECT(this.m_level);
707	                    this.PlayMagicPotAnimations(collectAnimConfigs);
708	                    // 播放收集音效（suppressCollectSfx=true 時靜音）
709	                    if (!suppressCollectSfx) {
710	                        AudioManager.Play(AudioManager.AudioClips.MagicPotCollect);
711	                    }
712	                    await Define.Wait(this, MagicPotController.COLLECT_WAIT_DURATION);
713	                }
714	            }
715	
716	            if (!isPlayUpgradeEffectFinish) {
717	                // 播放所有升級效果
718	                for (const upgradeData of data) {
719	                    await this.PlayUpgradeEffect(upgradeData);
720	                }
721	            }
722	
723	            // log(`MagicPot: 所有收集效果完成 (共 ${platePositions.length} 個)`);
724	        } catch (error) {
725	            log('[MagicPotController] PlayCollectEffect error:', error);
726	        } finally {
727	            // 不論成功/失敗/提前 return，都要執行回調，確保流程不會卡住
728	            this.InvokeSafeCallback(callback, "PlayCollectEffect");
729	        }
730	    }
