732	    /**
733	     * @ch 安全呼叫 callback（避免 callback throw 造成流程 rejected）
734	     * @param callback 回調
735	     * @param context 呼叫來源（用於 log）
736	     */
737	    private InvokeSafeCallback(callback?: () => void, context: string = ""): void {
738	        if (!callback) return;
739	        try {
740	            callback();
741	        } catch (error) {
742	            const ctx = context ? ` ${context}` : "";
743	            log(`[MagicPotController]${ctx} callback error:`, error);
744	        }
745	    }
