747	    /**
748	     * @ch 安全呼叫帶參數 callback（避免 callback throw 影響事件流程）
749	     * @param callback 回調
750	     * @param param 參數
751	     * @param context 呼叫來源（用於 log）
752	     */
753	    private InvokeSafeCallbackWithParam<T>(callback: ((param: T) => void) | undefined, param: T, context: string = ""): void {
754	        if (!callback) return;
755	        try {
756	            callback(param);
757	        } catch (error) {
758	            const ctx = context ? ` ${context}` : "";
759	            log(`[MagicPotController]${ctx} callback error:`, error);
760	        }
761	    }
