780	    /**
781	     * @ch 播放升級效果
782	     * @param data 資料
783	     * @param callback 完成回調
784	     */
785	    private async PlayUpgradeEffect(data: IEnergyLevelUpgradeInfo, callback?: () => void): Promise<void> {
786	        try {
787	            // log( "PlayUpgradeEffect 開始" );
788	
789	            if (!this.m_isInit) {
790	                log("PlayUpgradeEffect 失敗: 未初始化");
791	                return;
792	            }
793	
794	            if (!data) {
795	                log("PlayUpgradeEffect 失敗: 資料為空");
796	                return;
797	            }
798	
799	            // 先記錄 server 等級（不論後續 BC-13 / BC-9 是否早退，GetLevel() 都該反映最新 server 值，避免 cache 落後）
800	            this.m_serverLevel = data.EnergyLevel;
801	
802	            if (this.m_level === MagicPotController.BINGO_LEVEL) {
803	                log("PlayUpgradeEffect 已經是 Bingo 等級，不進行升級");
804	                return;
805	            }
806	
807	            if (data.Upgrade) {
808	                // log("PlayUpgradeEffect 升級 新等級: " + data.EnergyLevel);
809	
810	                const oldLevel = this.m_level;
811	                const newLevel = MagicPotController.ConvertServerLevelToClient(data.EnergyLevel);
812	
813	                // BC-9：映射後 client 等級相同（例如 server 0→1 都對應 client 0）→ 不播 LVUP 動畫
814	                if (newLevel === oldLevel) {
815	                    return;
816	                }
817	
818	                // 播放音效
819	                const audioClip = newLevel === MagicPotController.BINGO_LEVEL ? AudioManager.AudioClips.MagicPotFull : AudioManager.AudioClips.MagicPotUpgrade;
820	                AudioManager.Play(audioClip);
821	
822	                // 根據升級目標選擇動畫
823	                if (newLevel === MagicPotController.BINGO_LEVEL) {
824	                    const upgradeAnimConfigs = MAGIC_POT_ANIMATION.UPGRADE_TO_BINGO(oldLevel);
825	                    this.StopTracksNotIn(upgradeAnimConfigs);
826	                    await this.PlayMagicPotAnimations(upgradeAnimConfigs);
827	                } else {
828	                    const upgradeAnimConfigs = MAGIC_POT_ANIMATION.UPGRADE_TO_NEXT(oldLevel, newLevel);
829	                    this.StopTracksNotIn(upgradeAnimConfigs);
830	                    await this.PlayMagicPotAnimations(upgradeAnimConfigs);
831	                }
832	
833	                this.SetClientLevelInternal(newLevel, true);
834	            }
835	            else {
836	                const newLevel = MagicPotController.ConvertServerLevelToClient(data.EnergyLevel);
837	                if (newLevel !== this.m_level) {
838	                    log("PlayUpgradeEffect 等級不同就設回原本等級");
839	                    this.SetClientLevelInternal(newLevel, false);
840	                }
841	                // else: 等級相同，無動作
842	            }
843	        } catch (error) {
844	            log('[MagicPotController] PlayUpgradeEffect error:', error);
845	        } finally {
846	            // 執行完成回調
847	            this.InvokeSafeCallback(callback, "PlayUpgradeEffect");
848	        }
849	    }
