851	    /**
852	     * @ch 停止所有動畫並清理資源
853	     */
854	    private StopAllAnimations(): void {
855	        // 停止所有 Tween
856	        this.m_currentTweens.forEach(tween => {
857	            if (tween) {
858	                tween.stop();
859	            }
860	        });
861	        this.m_currentTweens = [];
862	
863	        // 銷毀所有效果節點
864	        this.m_collectEffectNodes.forEach(node => {
865	            if (node && node.isValid) {
866	                node.destroy();
867	            }
868	        });
869	        this.m_collectEffectNodes = [];
