872	    /**
873	     * @ch 開始單個貝茲動畫（支援多個並行）
874	     * @param startNode 起始節點
875	     * @param effectNode 效果節點
876	     * @param onComplete 完成回調
877	     */
878	    private StartBezierAnimation(startNode: Node, effectNode: Node, onComplete: () => void): void {
879	        if (!effectNode || !this.m_magicPot) {
880	            log("MagicPot: 收集效果或魔法罐節點不存在");
881	            if (onComplete) onComplete();
882	            return;
883	        }
884	
885	        // 取得起始和結束位置
886	        const startPos = startNode.getWorldPosition();
887	        const endPos = this.m_magicPot.getWorldPosition();
888	
889	        // 設定初始位置並顯示節點
890	        effectNode.active = true;
891	        effectNode.setWorldPosition(startPos);
892	
893	        // 使用 Common.BezierMoveToWithTween 建立貝茲動畫
894	        const { tween: tweenInstance, done } = Common.BezierMoveToWithTween(
895	            effectNode,
896	            startPos,
897	            endPos,
898	            MagicPotController.COLLECT_DURATION,
899	            () => {
900	                // 動畫完成，清理節點
901	                if (effectNode && effectNode.isValid) {
902	                    effectNode.destroy();
903	                }
904	
905	                // 從陣列中移除效果節點
906	                const nodeIndex = this.m_collectEffectNodes.indexOf(effectNode);
907	                if (nodeIndex > -1) {
908	                    this.m_collectEffectNodes.splice(nodeIndex, 1);
909	                }
910	
911	                // 從 tween 陣列中移除
912	                if (tweenInstance) {
913	                    const tweenIndex = this.m_currentTweens.indexOf(tweenInstance);
914	                    if (tweenIndex > -1) {
915	                        this.m_currentTweens.splice(tweenIndex, 1);
916	                    }
917	                }
918	
919	                // 如果所有動畫都完成了，移除旋轉監聽
920	                if (this.m_currentTweens.length === 0) {
921	                }
922	
923	                // 執行完成回調
924	                onComplete?.();
925	            }
926	        );
927	
928	        // 如果 tween 建立成功，加入追蹤陣列並啟動
929	        if (tweenInstance) {
930	            this.m_currentTweens.push(tweenInstance);
931	            tweenInstance.start();
932	        } else {
933	            // tween 建立失敗，直接執行回調
934	            log("MagicPot: 建立 Bezier tween 失敗");
935	            onComplete?.();
936	        }
937	    }
938	
939	    /**
940	     * @ch 播放魔法罐動畫
941	     * @param config 動畫配置
942	     * @returns
943	     */
944	    private PlayMagicPotAnimation(config: MagicPotAnim) : Promise<void> {
945	        return this.PlaySpineAnimation(config.trackIdx, config.name, config.loop);
946	    }
947	
948	    /**
949	     * @ch 並行播放多個魔法罐動畫
950	     * @param configs 動畫配置陣列
951	     * @returns
952	     */
953	    private async PlayMagicPotAnimations(configs: MagicPotAnim[]): Promise<void> {
954	        if (!configs || configs.length === 0) {
955	            return;
956	        }
957	
958	        // 並行播放所有動畫
959	        const promises = configs.map(config =>
960	            this.PlaySpineAnimation(config.trackIdx, config.name, config.loop)
961	        );
962	
963	        await Promise.all(promises);
964	    }
965	
966	    /**
967	     * @ch 播放魔法罐動畫
968	     * @param trackIdx 軌道索引
969	     * @param animName 動畫名稱
970	     * @param isLoop 是否循環
971	     * @param needRest 是否需要重置
972	     */
973	    private async PlaySpineAnimation(trackIdx: number, animName: string, isLoop: boolean = false, needRest: boolean = false): Promise<void> {
974	        // 若同一 track 已在播相同的循環動畫，跳過以避免重置造成停頓
975	        if (isLoop) {
976	            const current = this.ActiveSpine.getCurrent(trackIdx);
977	            if (current?.animation?.name === animName) {
978	                return;
979	            }
980	        }
981	        await SpineKit.PlayAnimation(this.ActiveSpine, animName, isLoop, trackIdx, null, needRest);
982	    }
983	
984	    /**
985	     * @ch 根據等級播放待機動畫 (Idle + LV?)
986	     * @param level 目標等級 client 端 (0-based: 0=LV1, 1=LV2, 2=LV3, 3=LVBingo)
987	     */
988	    private PlayLevelAnimations(level: number): void {
989	        // 錯誤處理：檢查 level 是否在有效範圍內
990	        if (level < 0) {
991	            log(`[MagicPotController] PlayLevelAnimations: level ${level} 小於 0，已調整為 0`);
992	            level = 0;
993	        }
994	
995	        // 魔法罐最多支援 4 個等級 (0=LV1, 1=LV2, 2=LV3, 3=LVBingo)
996	        if (level > MagicPotController.BINGO_LEVEL) {
997	            log(`[MagicPotController] PlayLevelAnimations: level ${level} 超出最大等級 ${MagicPotController.BINGO_LEVEL}，已調整為 ${MagicPotController.BINGO_LEVEL}`);
998	            level = MagicPotController.BINGO_LEVEL;
999	        }
1000	
1001	        // 播放待機動畫組合：Idle + LV?
1002	        const animConfigs = MAGIC_POT_ANIMATION.IDLE_ANIM(level);
1003	        this.StopTracksNotIn(animConfigs);
1004	        this.PlayMagicPotAnimations(animConfigs);
1005	    }
1006	
1007	    /**
1008	     * @ch 停止魔法罐動畫
1009	     * @param config 動畫配置
1010	     */
1011	    private StopMagicPotAnimation(config: MagicPotAnim): void {
1012	        this.StopSpineAnimation(config.trackIdx);
1013	    }
1014	
1015	    /**
1016	     * @ch 停止魔法罐動畫
1017	     * @param trackIdx 軌道索引
1018	     */
1019	    private StopSpineAnimation(trackIdx: number): void {
1020	        this.ActiveSpine.clearTrack(trackIdx);
1021	        this.ActiveSpine.setToSetupPose();
1022	    }
1023	
1024	    /**
1025	     * @ch 清除新組合不包含的 track，保留已在播的 track（如 Idle），避免 setToSetupPose 造成畫面頓感
1026	     */
1027	    private StopTracksNotIn(configs: MagicPotAnim[]): void {
1028	        // @ch 建立 trackIdx -> name 的映射，同時比對 track 和動畫名稱才保留
1029	        const keepMap = new Map(configs.map(c => [c.trackIdx, c.name]));
1030	        const maxTrackIdx = LV_START_TRACK_IDX + MagicPotController.BINGO_LEVEL;
1031	        for (let i = 0; i < maxTrackIdx + 1; i++) {
1032	            const currentEntry = this.ActiveSpine.getCurrent(i);
1033	            const currentName = currentEntry?.animation?.name;
1034	            const keepName = keepMap.get(i);
1035	            if (keepName === undefined || currentName !== keepName) {
1036	                this.ActiveSpine.clearTrack(i);
1037	            }
1038	        }
1039	    }
1040	
1041	    /**
1042	     * @ch 停止所有魔法罐動畫
1043	     */
1044	    private StopAllSpineAnimations(): void {
1045	        const maxTrackIdx = LV_START_TRACK_IDX + MagicPotController.BINGO_LEVEL;
1046	        for (let i = 0; i < maxTrackIdx + 1; i++) {
1047	            this.ActiveSpine.clearTrack(i);
1048	        }
1049	        this.ActiveSpine.setToSetupPose();
1050	    }
1051	
1052	    /**
1053	     * @ch 切換UI
1054	     * @param isFreeGame 是否free game (true=進入FG, false=回到普通模式)
1055	     * @param callback 完成回調
1056	     * @returns
1057	     */
1058	    private async SwitchUI(isFreeGame: boolean, callback?: () => void): Promise<void> {
1059	        try {
1060	            this.StopAllSpineAnimations();
1061	            this.SetFreeSpinTextNodesShow(isFreeGame);
1062	            if (isFreeGame) {
1063	                // 播放 FG_IDLE
1064	                await this.PlayMagicPotAnimations(MAGIC_POT_ANIMATION.FG_IDLE);
1065	            }
1066	            else {
1067	                // 回到普通模式：播放 BottleFloat
1068	                // 注意：m_level 已是 client level，必須走 SetClientLevelInternal 避免 client→client 二次轉換
1069	                this.StopAllSpineAnimations();
1070	                this.SetClientLevelInternal(this.m_level, true);
1071	            }
1072	        } catch (error) {
1073	            log('[MagicPotController] SwitchUI error:', error);
1074	        } finally {
1075	            // 不論成功/失敗，都要執行回調，確保流程不會卡住
1076	            this.InvokeSafeCallback(callback, "SwitchUI");
1077	        }
1078	    }
1079	
1080	    /**
1081	     * @ch 播放進入free game動畫
1082	     * @param callback 完成回調
1083	     * @returns
1084	     */
1085	    private async PlayToFreeGame(callback?: () => void): Promise<void> {
1086	        try {
1087	            this.StopAllSpineAnimations();
1088	            await this.PlayMagicPotAnimation(MAGIC_POT_ANIMATION.BINGO_TO_FG);
1089	        } catch (error) {
1090	            log('[MagicPotController] PlayToFreeGame error:', error);
1091	        } finally {
1092	            this.InvokeSafeCallback(callback, "PlayToFreeGame");
1093	        }
1094	    }
1095	    
1096	    /**
1097	     * @ch 獲取免費遊戲回合數字節點
1098	     * @returns 免費遊戲回合數字節點
1099	     */
1100	    private GetFreeGameRoundNumberNode(): Node {
1101	        if (this.m_freeGameRoundNumberNode) {
1102	            return this.m_freeGameRoundNumberNode;
1103	        }
1104	        eventManager.Dispatch(FREE_GAME_ROUND_UI_EVENT.GET_ROUND_NUMBER_NODE, (node: Node) => {
1105	            if (node) {
1106	                this.m_freeGameRoundNumberNode = node;
1107	            }
1108	        });
1109	        return this.m_freeGameRoundNumberNode;
1110	    }
1111	
1112	    /**
1113	     * @ch 把回合數字節點推入對應方向的 RootNode
1114	     */
1115	    private PushToFreeGameNumberRootNode(): void {
1116	        const node = this.GetFreeGameRoundNumberNode();
1117	        if (!node) {
1118	            log('[MagicPotController] PushToFreeGameNumberRootNode: 回合數字節點不存在');
1119	            return;
1120	        }
1121	        const rootNode = this.m_isLandscape
1122	            ? this.m_freeGameNumberRootNodes[0]
1123	            : this.m_freeGameNumberRootNodes[1];
1124	        if (!rootNode) {
1125	            log('[MagicPotController] PushToFreeGameNumberRootNode: RootNode 不存在');
1126	            return;
1127	        }
1128	        this.m_freeGameRoundNumberPopupData = Common.PushNode(node, rootNode);
1129	    }
1130	
1131	    /**
1132	     * @ch 把回合數字節點從 RootNode 放回原位
1133	     */
1134	    private PopToFreeGameNumberRootNode(): void {
1135	        if (!this.m_freeGameRoundNumberPopupData) {
1136	            log('[MagicPotController] PopToFreeGameNumberRootNode: 節點尚未推入，略過');
1137	            return;
1138	        }
1139	        Common.PopNode(this.m_freeGameRoundNumberPopupData);
1140	        this.m_freeGameRoundNumberPopupData = null;
1141	    }
1142	
1143	    /**
1144	     * @ch 設置免費遊戲Spin文字節點顯示 (true: 顯示, false: 隱藏)
1145	     * @param isShow 是否顯示
1146	     */
1147	    private SetFreeSpinTextNodesShow(isShow: boolean): void {
1148	        if (!this.m_freeSpinTextNodes || this.m_freeSpinTextNodes.length === 0) {
1149	            log('[MagicPotController] SetFreeSpinTextNodesShow: 免費遊戲Spin文字節點不存在');
