1177	    /**
1178	     * @ch 檢查測試按鍵
1179	     */
1180	    private CheckTestKeyCode(event: EventKeyboard) {
1181	        return;
1182	        log("CheckTestKeyCode", event.keyCode);
1183	        switch (event.keyCode) {
1184	            case KeyCode.DIGIT_0:
1185	                this.StopAllSpineAnimations();
1186	                this.SetLevel(0);
1187	                break;
1188	
1189	            case KeyCode.DIGIT_9:
1190	                this.StopAllSpineAnimations();
1191	                const newLevel = (this.m_level + 1) % (MagicPotController.BINGO_LEVEL + 1);
1192	                this.SetLevel(newLevel);
