import { _decorator, Component, log, Node, Tween, Prefab, sp, input, Input, EventKeyboard, KeyCode, screen } from 'cc';
import { commonGameManager, eventManager } from 'db://astarte-framework/Managers';
import Game_Define from '../Game_Define';
import GameView from '../GameView';
import { Common, PopupNodeData } from '../Common/Common';
/** Local stub interface - IEnergyLevelUpgradeInfo was removed from new protocol */
interface IEnergyLevelUpgradeInfo { Upgrade?: boolean; EnergyLevel?: number; }
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
import { Define, tools } from 'db://astarte-framework/utilis';
import { FLY_EVENT } from '../FlyManager';
import { AudioManager } from '../Audio/AudioManager';
import { FREE_GAME_ROUND_UI_EVENT } from '../FreeGame/FreeGameRoundUI';
import { DEBUG } from 'cc/env';

const { ccclass, property } = _decorator;

export const MAGIC_POT_EVENT = {
    /**@ch
     * 初始化
     * @param gameView 遊戲視窗
     * @param level 等級
     */
    INIT: "MAGIC_POT_INIT",

    /**@ch
     * 設置等級
     * @param level 等級（server 端 0~6，內部映射為 client 0~3。對照：0,1→0｜2,3→1｜4,5→2｜6→3）
     */
    SET_LEVEL: "MAGIC_POT_SET_LEVEL",

    /**@ch
     * 獲取等級
     * @param func(level: number) 回傳等級
     */
    GET_LEVEL: "MAGIC_POT_GET_LEVEL",

    /**@ch
     * 播放收集效果
     * @param (必填) platePositions 盤面位置陣列
     * @param (必填) IEnergyLevelUpgradeInfo[] 資料陣列
     * @param (選填) callback 完成回調
     * @param (選填) isPlayCollectEffect 是否播放收集效果
     * @param (選填) suppressCollectSfx 是否靜音 MagicPotCollect 音效（不影響 FlyToMagicPot；預設 false）
     */
    PLAY_COLLECT_EFFECT: "MAGIC_POT_PLAY_COLLECT_EFFECT",

    /**@ch
     * 播放升級效果
     * @param IEnergyLevelUpgradeInfo 資料
     * @param callback 完成回調
     */
    PLAY_UPGRADE_EFFECT: "MAGIC_POT_PLAY_UPGRADE_EFFECT",

    /**@ch
     * 切換UI
     * @param (必填) isFreeGame 是否free game
     * @param (選填) callback 完成回調
     */
    SWITCH_UI: "MAGIC_POT_SWITCH_UI",

    /**@ch
     * 播放進入free game動畫
     * @param (選填) callback 完成回調
     */
    PLAY_TO_FREE_GAME: "MAGIC_POT_PLAY_TO_FREE_GAME",

    /**@ch
     * 獲取節點
     * @param (選填) callback 完成回調
     */
    GET_NODE: "MAGIC_POT_GET_NODE",

    /**@ch
     * 推入免費遊戲回合數字節點
     */
    PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE: "MAGIC_POT_PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE",

    /**@ch
     * 彈出免費遊戲回合數字節點
     */
    POP_TO_FREE_GAME_NUMBER_ROOT_NODE: "MAGIC_POT_POP_TO_FREE_GAME_NUMBER_ROOT_NODE",
}

// 定義型別（可放在檔案頂部附近）
type MagicPotAnim = { name: string; trackIdx: number, loop: boolean };

/**@ch 等級開始Track索引*/
const LV_START_TRACK_IDX: number = 2;

// 取代既有的 MAGIC_POT_ANIMATION
export const MAGIC_POT_ANIMATION = {
    IDLE: { name: "Idle", trackIdx: 0, loop: true } as MagicPotAnim,
    HIT: { name: "Hit", trackIdx: 1, loop: false } as MagicPotAnim,

    // 升級到下一階：回傳 [Idle, LVUPXtoY] 的組合
    UPGRADE_TO_NEXT: (fromLevel: number, toLevel: number): MagicPotAnim[] => {
        return [
            { name: "Idle", trackIdx: 0, loop: true } as MagicPotAnim,
            { name: `LVUP${fromLevel + 1}to${toLevel + 1}`, trackIdx: 1, loop: false } as MagicPotAnim,
        ];
    },

    // 升級到 Bingo：回傳 [Idle, LVUPXtoBingo] 的組合
    UPGRADE_TO_BINGO: (fromLevel: number): MagicPotAnim[] => {
        return [
            { name: "Idle", trackIdx: 0, loop: true } as MagicPotAnim,
            { name: `LVUP${fromLevel + 1}toBingo`, trackIdx: 1, loop: false } as MagicPotAnim,
        ];
    },

    // 收集效果：回傳 [Idle, Hit, LV?] 的組合
    COLLECT_EFFECT: (level: number): MagicPotAnim[] => {
        const lvName = level === MagicPotController.BINGO_LEVEL ? "LVBingo" : `LV${level + 1}`;
        return [
            { name: "Idle", trackIdx: 0, loop: true } as MagicPotAnim,
            { name: "Hit", trackIdx: 1, loop: false } as MagicPotAnim,
            { name: lvName, trackIdx: LV_START_TRACK_IDX + level, loop: true } as MagicPotAnim,
        ];
    },

    // 待機動畫：回傳 [Idle, LV?] 的組合
    IDLE_ANIM: (level: number): MagicPotAnim[] => {
        const lvName = level === MagicPotController.BINGO_LEVEL ? "LVBingo" : `LV${level + 1}`;
        return [
            { name: "Idle", trackIdx: 0, loop: true } as MagicPotAnim,
            { name: lvName, trackIdx: LV_START_TRACK_IDX + level, loop: true } as MagicPotAnim,
        ];
    },

    // FG待機動畫
    FG_IDLE: [
        { name: "Idle", trackIdx: 0, loop: true } as MagicPotAnim,
        { name: "FG_Idle", trackIdx: 1, loop: true } as MagicPotAnim,
    ] as MagicPotAnim[],

    // 集滿轉到FG動畫 
    BINGO_TO_FG:  { name: "LVBingotoFG", trackIdx: 1, loop: false } as MagicPotAnim,
} as const;

@ccclass('MagicPotController')
export class MagicPotController extends Component {
    //#region Constants
    /**@ch 需要註冊的事件列表 */
    private static readonly EVENTS_TO_REGISTER = [
        MAGIC_POT_EVENT.INIT,
        MAGIC_POT_EVENT.SET_LEVEL,
        MAGIC_POT_EVENT.GET_LEVEL,
        MAGIC_POT_EVENT.PLAY_COLLECT_EFFECT,
        MAGIC_POT_EVENT.PLAY_UPGRADE_EFFECT,
        MAGIC_POT_EVENT.SWITCH_UI,
        MAGIC_POT_EVENT.PLAY_TO_FREE_GAME,
        MAGIC_POT_EVENT.GET_NODE,
        MAGIC_POT_EVENT.PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE,
        MAGIC_POT_EVENT.POP_TO_FREE_GAME_NUMBER_ROOT_NODE,
        Game_Define.EVENT.DEVICE_ROTATION,
    ];

    /**@ch 魔法罐最高等級（Bingo 等級，client 端 0~3 的最高值）*/
    static readonly BINGO_LEVEL: number = 3;

    /**@ch 收集效果動畫總時長(秒)*/
    private static readonly COLLECT_DURATION: number = 0.5;

    /**@ch 收集等待動畫時長(秒)也是間隔時長*/
    private static readonly COLLECT_WAIT_DURATION: number = 0.5;
    //#endregion Constants

    //#region Properties
    @property( {
        type: Node,
        tooltip: "魔法罐"
    } )
    m_magicPot: Node = null;

    /**@ch 收集效果 Prefab*/
    @property( {
        type: Prefab,
        tooltip: "收集效果 Prefab"
    } )
    m_collectEffect: Prefab = null;

    @property( {
        type: Node,
        tooltip: "飛行目標節點"
    } )
    m_flyTargetNode: Node = null;

    /**@ch 直版魔法罐*/
    @property( {
        type: Node,
        tooltip: "魔法罐（直版）"
    } )
    m_magicPotPortrait: Node = null;

    /**@ch 免費遊戲回合數字掛載根節點*/
    @property( {
        type: [Node],
        tooltip: "免費遊戲回合數字掛載根節點"
    } )
    m_freeGameNumberRootNodes: Node[] = [];

    /**@ch 免費遊戲Spin文字節點*/
    @property( {
        type: [Node],
        tooltip: "免費遊戲Spin文字節點"
    } )
    m_freeSpinTextNodes : Node[] = [];
    //#endregion Properties

    //#region Properties
    /**@ch 等級（client 顯示等級，0~BINGO_LEVEL=3）*/
    private m_level: number;

    /**@ch 最近一次 server 等級（0~6），供 GetLevel() 對外回傳維持原契約；m_level 為其映射結果 */
    private m_serverLevel: number = 0;

    /**@ch 是否初始化*/
    private m_isInit: boolean;

    /**@ch 收集效果實例節點陣列*/
    private m_collectEffectNodes: Node[] = [];

    /**@ch 當前動畫 Tween 陣列*/
    private m_currentTweens: Tween<any>[] = [];

    /**@ch 遊戲視圖*/
    private m_gameView: GameView = null;

    /**@ch 是否註冊事件*/
    private m_isEventRegistered: boolean = false;

    /**@ch 魔法罐Spine（橫版）*/
    private m_magicPotSpine : sp.Skeleton = null;

    /**@ch 魔法罐Spine（直版）*/
    private m_magicPotPortraitSpine : sp.Skeleton = null;

    /**@ch 當前是否為橫版*/
    private m_isLandscape: boolean = true;

    /**@ch 取得目前顯示中的 Spine */
    private get ActiveSpine(): sp.Skeleton {
        return this.m_isLandscape ? this.m_magicPotSpine : this.m_magicPotPortraitSpine;
    }

    /**@ch 免費遊戲回合數字節點*/
    private m_freeGameRoundNumberNode: Node = null;

    /**@ch 免費遊戲回合數字節點的 Push 資料（用於 PopNode 還原）*/
    private m_freeGameRoundNumberPopupData: PopupNodeData = null;
    //#endregion Properties

    //#region Methods
    /**
     * @ch 檢查節點或組件是否有效
     * @param obj 要檢查的物件
     * @param objName 物件名稱（用於錯誤訊息）
     * @returns 是否有效
     */
    private IsValid<T>( obj: T, objName: string ): obj is NonNullable<T>
    {
        if (!obj) {
            log(`[MagicPotController] ${objName} is null or undefined`);
            return false;
        }
        return true;
    }

    onLoad()
    {
        this.RegisterEvent();
        this.RegisterTestKeyCodes();

        if (!this.IsValid(this.m_magicPot, 'm_magicPot')) {
            return;
        }

        this.m_magicPotSpine = this.m_magicPot.getComponent(sp.Skeleton);
        if (!this.IsValid(this.m_magicPotSpine, 'm_magicPotSpine')) {
            log('[MagicPotController] Failed to get Skeleton component from m_magicPot');
        }

        if (this.m_magicPotPortrait) {
            this.m_magicPotPortraitSpine = this.m_magicPotPortrait.getComponent(sp.Skeleton);
            if (!this.IsValid(this.m_magicPotPortraitSpine, 'm_magicPotPortraitSpine')) {
                log('[MagicPotController] Failed to get Skeleton component from m_magicPotPortrait');
            }
        }

        // 依初始螢幕方向設定顯示
        const windowSize = screen.windowSize;
        this.m_isLandscape = windowSize.width >= windowSize.height;
        this.m_magicPot.active = this.m_isLandscape;
        if (this.m_magicPotPortrait) {
            this.m_magicPotPortrait.active = !this.m_isLandscape;
        }
    }

    onDestroy()
    {
        this.UnregisterEvent();
        this.UnregisterTestKeyCodes();

        // 停止所有動畫並移除旋轉監聽
        this.StopAllAnimations();
    }

    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        if (this.m_isEventRegistered) return;

        MagicPotController.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        this.m_isEventRegistered = true;
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent() {
        if (!this.m_isEventRegistered) return;

        MagicPotController.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });

        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件
     * @param event 事件
     * @param args 參數
     */
    OnEvent( event: string, ...args: any[] )
    {
        switch (event) {
            /**@ch 初始化*/
            case MAGIC_POT_EVENT.INIT:
                if (!this.ValidateInitParams(args)) {
                    log('[MagicPotController] INIT event requires: (gameView: GameView, level: number)');
                    return;
                }
                this.Init(args[0], args[1]);
                break;

            /**@ch 設置等級*/
            case MAGIC_POT_EVENT.SET_LEVEL:
                if (!this.ValidateLevelParam(args)) {
                    log('[MagicPotController] SET_LEVEL event requires: (level: number)');
                    return;
                }
                this.SetLevel(args[0]);
                break;

            /**@ch 獲取等級*/
            case MAGIC_POT_EVENT.GET_LEVEL:
                if (!this.ValidateCallbackParam(args)) {
                    log('[MagicPotController] GET_LEVEL event requires: (callback: (level: number) => void)');
                    return;
                }
                this.InvokeSafeCallbackWithParam<number>(args[0], this.GetLevel(), "GET_LEVEL");
                break;

            /**@ch 播放收集效果*/
            case MAGIC_POT_EVENT.PLAY_COLLECT_EFFECT:
                if (!this.ValidateCollectEffectParams(args)) {
                    log('[MagicPotController] PLAY_COLLECT_EFFECT event requires: (platePositions: number[], data: IEnergyLevelUpgradeInfo[], callback?: () => void, isPlayCollectEffect?: boolean, suppressCollectSfx?: boolean)');
                    return;
                }
                this.PlayCollectEffect(args[0], args[1], args[2], args[3], args[4]);
                break;

            /**@ch 播放升級效果*/
            case MAGIC_POT_EVENT.PLAY_UPGRADE_EFFECT:
                if (!this.ValidateUpgradeEffectParams(args)) {
                    log('[MagicPotController] PLAY_UPGRADE_EFFECT event requires: (data: IEnergyLevelUpgradeInfo, callback?: () => void)');
                    return;
                }
                this.PlayUpgradeEffect(args[0], args[1]);
                break;

            /**@ch 切換UI*/
            case MAGIC_POT_EVENT.SWITCH_UI:
                if (!this.ValidateSwitchUIParams(args)) {
                    log('[MagicPotController] SWITCH_UI event requires: (isFreeGame: boolean, callback?: () => void)');
                    return;
                }
                this.SwitchUI(args[0], args[1]);
                break;

            /**@ch 播放進入free game動畫*/
            case MAGIC_POT_EVENT.PLAY_TO_FREE_GAME:
                if (!this.ValidateSimpleCallbackParam(args)) {
                    log('[MagicPotController] PLAY_TO_FREE_GAME event requires: (callback?: () => void)');
                    return;
                }
                this.PlayToFreeGame(args[0]);
                break;

            /**@ch 獲取節點*/
            case MAGIC_POT_EVENT.GET_NODE:
                if (!this.ValidateNodeCallbackParam(args)) {
                    log('[MagicPotController] GET_NODE event requires: (callback?: (node: Node) => void)');
                    return;
                }
                this.InvokeSafeCallbackWithParam<Node>(args[0], this.node, "GET_NODE");
                break;

            /**@ch 推入免費遊戲回合數字節點*/
            case MAGIC_POT_EVENT.PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE:
                this.PushToFreeGameNumberRootNode();
                break;

            /**@ch 彈出免費遊戲回合數字節點*/
            case MAGIC_POT_EVENT.POP_TO_FREE_GAME_NUMBER_ROOT_NODE:
                this.PopToFreeGameNumberRootNode();
                break;

            /**@ch 裝置旋轉*/
            case Game_Define.EVENT.DEVICE_ROTATION:
                this.OnDeviceRotation();
                break;
        }
    }

    /**
     * @ch 驗證初始化參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateInitParams(args: any[]): args is [GameView, number] {
        return args.length >= 2 &&
            args[0] != null && // GameView 物件
            typeof args[1] === 'number';
    }

    /**
     * @ch 驗證等級參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateLevelParam(args: any[]): args is [number] {
        return args.length >= 1 && typeof args[0] === 'number';
    }

    /**
     * @ch 驗證回調參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateCallbackParam(args: any[]): args is [((level: number) => void)?] {
        return args.length === 0 ||
            (args.length >= 1 && (typeof args[0] === 'function' || args[0] === undefined));
    }

    /**
     * @ch 驗證無參數回調
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateSimpleCallbackParam(args: any[]): args is [(() => void)?] {
        return args.length === 0 ||
            (args.length >= 1 && (typeof args[0] === 'function' || args[0] === undefined));
    }

    /**
     * @ch 驗證節點回調參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateNodeCallbackParam(args: any[]): args is [((node: Node) => void)?] {
        return args.length === 0 ||
            (args.length >= 1 && (typeof args[0] === 'function' || args[0] === undefined));
    }

    /**
     * @ch 驗證收集效果參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateCollectEffectParams(args: any[]): args is [number[], IEnergyLevelUpgradeInfo[], (() => void)?, boolean?, boolean?] {
        return args.length >= 2 &&
            Array.isArray(args[0]) &&
            args[0].every((item: any) => typeof item === 'number') &&
            Array.isArray(args[1]) &&
            (args.length < 3 || typeof args[2] === 'function' || args[2] === undefined) &&
            (args.length < 4 || typeof args[3] === 'boolean' || args[3] === undefined) &&
            (args.length < 5 || typeof args[4] === 'boolean' || args[4] === undefined);
    }

    /**
     * @ch 驗證升級效果參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateUpgradeEffectParams(args: any[]): args is [IEnergyLevelUpgradeInfo, (() => void)?] {
        return args.length >= 1 &&
            args[0] != null && // IEnergyLevelUpgradeInfo 物件
            (args.length < 2 || typeof args[1] === 'function' || args[1] === undefined);
    }

    /**
     * @ch 驗證切換UI參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateSwitchUIParams(args: any[]): args is [boolean, (() => void)?] {
        return args.length >= 1 &&
            typeof args[0] === 'boolean' &&
            (args.length < 2 || typeof args[1] === 'function' || args[1] === undefined);
    }

    /**
     * @ch 驗證顯示參數
     * @param args 參數陣列
     * @returns 是否為有效參數
     */
    private ValidateShowParam(args: any[]): args is [boolean] {
        return args.length >= 1 && typeof args[0] === 'boolean';
    }

    /**
     * @ch 裝置旋轉處理：切換顯示的 Spine 並重播當前狀態動畫
     */
    private OnDeviceRotation(): void {
        const windowSize = screen.windowSize;
        const newIsLandscape = windowSize.width >= windowSize.height;
        if (newIsLandscape === this.m_isLandscape) return;

        this.m_isLandscape = newIsLandscape;
        this.m_magicPot.active = this.m_isLandscape;
        if (this.m_magicPotPortrait) {
            this.m_magicPotPortrait.active = !this.m_isLandscape;
        }

        if (!this.m_isInit) return;

        // 若回合數字節點已掛載到 RootNode 上，改掛到新方向的 RootNode
        if (this.m_freeGameRoundNumberPopupData && this.m_freeGameRoundNumberNode) {
            const newRootNode = this.m_isLandscape
                ? this.m_freeGameNumberRootNodes[0]
                : this.m_freeGameNumberRootNodes[1];
            if (newRootNode) {
                this.m_freeGameRoundNumberNode.setParent(newRootNode);
            }
        }

        // 清除新 Spine 的殘留 track，確保從乾淨狀態重播
        this.StopAllSpineAnimations();

        // 切換後在新 Spine 上重播當前狀態動畫
        if (this.m_gameView?.IsFreeGame) {
            this.PlayMagicPotAnimations(MAGIC_POT_ANIMATION.FG_IDLE);
        } else {
            this.PlayLevelAnimations(this.m_level);
        }
    }

    /**
     * @ch 初始化
     * @param gameView 遊戲視窗
     * @param level 等級
     */
    Init(gameView: GameView, level: number) {
        this.m_gameView = gameView;
        this.SetLevel(level);
        this.m_isInit = true;
    }

    /**
     * @ch 將 server 端等級（0~6）映射為 client 端顯示等級（0~3）
     * 對照：0,1→0｜2,3→1｜4,5→2｜6→3
     * ⚠️ 非冪等：對 client 值再呼叫會得到 0,0,1,1，僅允許在 server 值進入時呼叫
     * @param serverLevel server 端能量等級
     * @returns client 端顯示等級（0~BINGO_LEVEL）
     */
    private static ConvertServerLevelToClient(serverLevel: number): number {
        if (serverLevel >= 6) return MagicPotController.BINGO_LEVEL;
        return Math.max(0, Math.floor(serverLevel / 2));
    }

    /**
     * @ch 設置等級（對外事件入口）
     * ⚠️ 契約：`level` 為 server 端等級（0~6），內部會映射為 client 等級。
     * 內部呼叫（已知值為 client level）請使用 `SetClientLevelInternal`，避免二次轉換。
     * @param level server 端等級
     * @param isPlayAnimation 是否播放動畫
     */
    SetLevel(level: number, isPlayAnimation: boolean = true) {
        this.m_serverLevel = level;
        const clientLevel = MagicPotController.ConvertServerLevelToClient(level);
        this.SetClientLevelInternal(clientLevel, isPlayAnimation);
    }

    /**
     * @ch 設置 client 等級（內部使用，跳過 server→client 映射）
     * ⚠️ 警告：傳入必須是已映射的 client level（0~BINGO_LEVEL=3），內部不再做轉換
     * @param clientLevel client 端顯示等級
     * @param isPlayAnimation 是否播放動畫
     */
    private SetClientLevelInternal(clientLevel: number, isPlayAnimation: boolean = true) {
        this.m_level = clientLevel;

        if (isPlayAnimation && this.m_gameView && !this.m_gameView.IsFreeGame) {
            this.PlayLevelAnimations(this.m_level);
        }
    }

    /**
     * @ch 獲取等級
     * 對外回傳 server 端等級（0~6），維持與舊版相同契約，避免呼叫端誤把回傳值再餵回 SetLevel 觸發二次轉換。
     * 若需要 client 顯示等級（0~3）請直接讀取 `m_level`（private）。
     * @returns server 端等級
     */
    GetLevel(): number {
        return this.m_serverLevel;
    }

    /**
     * @ch 播放收集效果
     * @param platePositions 盤面位置陣列
     * @param data 資料陣列
     * @param callback 完成回調（所有效果完成後執行）
     * @param isPlayCollectEffect 是否播放收集效果
     * @param suppressCollectSfx 是否靜音 MagicPotCollect 音效（FlyToMagicPot 不受此影響；預設 false）
     */
    async PlayCollectEffect(platePositions: number[], data: IEnergyLevelUpgradeInfo[], callback?: () => void, isPlayCollectEffect: boolean = true, suppressCollectSfx: boolean = false): Promise<void>
    {
        try {
            if (!this.m_isInit || !platePositions || platePositions.length === 0) {
                log("PlayCollectEffect 失敗: 未初始化或位置陣列無效");
                return;
            }

            if (!data || data.length === 0) {
                log("PlayCollectEffect 失敗: 資料為空");
                return;
            }

            // 停止所有進行中的動畫
            this.StopAllAnimations();

            const isPlaySequentially = platePositions.length < Game_Define.MAX_SCATTER;
            let isPlayUpgradeEffectFinish = !data || data.length === 0;

            // 判斷是否有升級資料並決定插入位置（隨機）
            const hasUpgrade = data && data.length === 1;
            let upgradeInsertIndex = -1;
            if (hasUpgrade) {
                if (platePositions.length === 1) {
                    // 只有一個位置，直接使用索引 0
                    upgradeInsertIndex = 0;
                } else {
                    // 建立索引陣列並打亂，取第一個作為隨機索引
                    const indexArray = Array.from({ length: platePositions.length }, (_, i) => i);
                    const shuffledArray = tools.GetRandomArrayBySeed(indexArray);
                    upgradeInsertIndex = shuffledArray[0];
                }
            }

            if (isPlayCollectEffect) {
                if (isPlaySequentially) {
                    // 依序播放每個位置的收集效果
                    for (let i = 0; i < platePositions.length; i++) {
                        const pos = platePositions[i];
                        const startNode = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos);
                        // 播放飛到魔法罐音效
                        AudioManager.Play(AudioManager.AudioClips.FlyToMagicPot);
                        await this.PlayCollectEffectByNode(startNode);

                        // 播放收集動畫組合：Idle + Hit + LV?
                        const collectAnimConfigs = MAGIC_POT_ANIMATION.COLLECT_EFFECT(this.m_level);
                        this.PlayMagicPotAnimations(collectAnimConfigs);
                        // 播放收集音效（suppressCollectSfx=true 時靜音）
                        if (!suppressCollectSfx) {
                            AudioManager.Play(AudioManager.AudioClips.MagicPotCollect);
                        }
                        await Define.Wait(this, MagicPotController.COLLECT_WAIT_DURATION);

                        // 如果當前位置是隨機選中的插入點，立即播放升級效果
                        if (i === upgradeInsertIndex && !isPlayUpgradeEffectFinish) {
                            // log("PlayCollectEffect 播放升級效果，位置: " + pos + "局號:" + commonGameManager.RoundIndex);
                            await this.PlayUpgradeEffect(data[0]);
                            isPlayUpgradeEffectFinish = true;
                        }
                    }
                } else {
                    // 一起播放所有位置的收集效果
                    const promises = platePositions.map(pos => {
                        const startNode = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos);
                        return this.PlayCollectEffectByNode(startNode);
                    });

                    // 播放飛到魔法罐音效
                    AudioManager.Play(AudioManager.AudioClips.FlyToMagicPot);

                    // 等待所有動畫完成
                    await Promise.all(promises);

                    // 播放收集動畫組合：Idle + Hit + LV?
                    const collectAnimConfigs = MAGIC_POT_ANIMATION.COLLECT_EFFECT(this.m_level);
                    this.PlayMagicPotAnimations(collectAnimConfigs);
                    // 播放收集音效（suppressCollectSfx=true 時靜音）
                    if (!suppressCollectSfx) {
                        AudioManager.Play(AudioManager.AudioClips.MagicPotCollect);
                    }
                    await Define.Wait(this, MagicPotController.COLLECT_WAIT_DURATION);
                }
            }

            if (!isPlayUpgradeEffectFinish) {
                // 播放所有升級效果
                for (const upgradeData of data) {
                    await this.PlayUpgradeEffect(upgradeData);
                }
            }

            // log(`MagicPot: 所有收集效果完成 (共 ${platePositions.length} 個)`);
        } catch (error) {
            log('[MagicPotController] PlayCollectEffect error:', error);
        } finally {
            // 不論成功/失敗/提前 return，都要執行回調，確保流程不會卡住
            this.InvokeSafeCallback(callback, "PlayCollectEffect");
        }
    }

    /**
     * @ch 安全呼叫 callback（避免 callback throw 造成流程 rejected）
     * @param callback 回調
     * @param context 呼叫來源（用於 log）
     */
    private InvokeSafeCallback(callback?: () => void, context: string = ""): void {
        if (!callback) return;
        try {
            callback();
        } catch (error) {
            const ctx = context ? ` ${context}` : "";
            log(`[MagicPotController]${ctx} callback error:`, error);
        }
    }

    /**
     * @ch 安全呼叫帶參數 callback（避免 callback throw 影響事件流程）
     * @param callback 回調
     * @param param 參數
     * @param context 呼叫來源（用於 log）
     */
    private InvokeSafeCallbackWithParam<T>(callback: ((param: T) => void) | undefined, param: T, context: string = ""): void {
        if (!callback) return;
        try {
            callback(param);
        } catch (error) {
            const ctx = context ? ` ${context}` : "";
            log(`[MagicPotController]${ctx} callback error:`, error);
        }
    }

    /**
     * @ch 播放單個位置的收集效果（用於平行播放）
     * @param startNode 起始節點
     */
    private async PlayCollectEffectByNode(startNode: Node): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!this.m_isInit || !startNode) {
                log("PlayCollectEffectByNode 失敗: 未初始化或起始節點無效");
                resolve();
                return;
            }
            const startNodeWorldPosition = startNode.getWorldPosition();
            const targetNode = this.m_flyTargetNode ? this.m_flyTargetNode.getWorldPosition() : this.m_magicPot.getWorldPosition();
            eventManager.Dispatch(FLY_EVENT.PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION, startNodeWorldPosition, targetNode, resolve);
        });
    }

    /**
     * @ch 播放升級效果
     * @param data 資料
     * @param callback 完成回調
     */
    private async PlayUpgradeEffect(data: IEnergyLevelUpgradeInfo, callback?: () => void): Promise<void> {
        try {
            // log( "PlayUpgradeEffect 開始" );

            if (!this.m_isInit) {
                log("PlayUpgradeEffect 失敗: 未初始化");
                return;
            }

            if (!data) {
                log("PlayUpgradeEffect 失敗: 資料為空");
                return;
            }

            // 先記錄 server 等級（不論後續 BC-13 / BC-9 是否早退，GetLevel() 都該反映最新 server 值，避免 cache 落後）
            this.m_serverLevel = data.EnergyLevel;

            if (this.m_level === MagicPotController.BINGO_LEVEL) {
                log("PlayUpgradeEffect 已經是 Bingo 等級，不進行升級");
                return;
            }

            if (data.Upgrade) {
                // log("PlayUpgradeEffect 升級 新等級: " + data.EnergyLevel);

                const oldLevel = this.m_level;
                const newLevel = MagicPotController.ConvertServerLevelToClient(data.EnergyLevel);

                // BC-9：映射後 client 等級相同（例如 server 0→1 都對應 client 0）→ 不播 LVUP 動畫
                if (newLevel === oldLevel) {
                    return;
                }

                // 播放音效
                const audioClip = newLevel === MagicPotController.BINGO_LEVEL ? AudioManager.AudioClips.MagicPotFull : AudioManager.AudioClips.MagicPotUpgrade;
                AudioManager.Play(audioClip);

                // 根據升級目標選擇動畫
                if (newLevel === MagicPotController.BINGO_LEVEL) {
                    const upgradeAnimConfigs = MAGIC_POT_ANIMATION.UPGRADE_TO_BINGO(oldLevel);
                    this.StopTracksNotIn(upgradeAnimConfigs);
                    await this.PlayMagicPotAnimations(upgradeAnimConfigs);
                } else {
                    const upgradeAnimConfigs = MAGIC_POT_ANIMATION.UPGRADE_TO_NEXT(oldLevel, newLevel);
                    this.StopTracksNotIn(upgradeAnimConfigs);
                    await this.PlayMagicPotAnimations(upgradeAnimConfigs);
                }

                this.SetClientLevelInternal(newLevel, true);
            }
            else {
                const newLevel = MagicPotController.ConvertServerLevelToClient(data.EnergyLevel);
                if (newLevel !== this.m_level) {
                    log("PlayUpgradeEffect 等級不同就設回原本等級");
                    this.SetClientLevelInternal(newLevel, false);
                }
                // else: 等級相同，無動作
            }
        } catch (error) {
            log('[MagicPotController] PlayUpgradeEffect error:', error);
        } finally {
            // 執行完成回調
            this.InvokeSafeCallback(callback, "PlayUpgradeEffect");
        }
    }

    /**
     * @ch 停止所有動畫並清理資源
     */
    private StopAllAnimations(): void {
        // 停止所有 Tween
        this.m_currentTweens.forEach(tween => {
            if (tween) {
                tween.stop();
            }
        });
        this.m_currentTweens = [];

        // 銷毀所有效果節點
        this.m_collectEffectNodes.forEach(node => {
            if (node && node.isValid) {
                node.destroy();
            }
        });
        this.m_collectEffectNodes = [];
    }

    /**
     * @ch 開始單個貝茲動畫（支援多個並行）
     * @param startNode 起始節點
     * @param effectNode 效果節點
     * @param onComplete 完成回調
     */
    private StartBezierAnimation(startNode: Node, effectNode: Node, onComplete: () => void): void {
        if (!effectNode || !this.m_magicPot) {
            log("MagicPot: 收集效果或魔法罐節點不存在");
            if (onComplete) onComplete();
            return;
        }

        // 取得起始和結束位置
        const startPos = startNode.getWorldPosition();
        const endPos = this.m_magicPot.getWorldPosition();

        // 設定初始位置並顯示節點
        effectNode.active = true;
        effectNode.setWorldPosition(startPos);

        // 使用 Common.BezierMoveToWithTween 建立貝茲動畫
        const { tween: tweenInstance, done } = Common.BezierMoveToWithTween(
            effectNode,
            startPos,
            endPos,
            MagicPotController.COLLECT_DURATION,
            () => {
                // 動畫完成，清理節點
                if (effectNode && effectNode.isValid) {
                    effectNode.destroy();
                }

                // 從陣列中移除效果節點
                const nodeIndex = this.m_collectEffectNodes.indexOf(effectNode);
                if (nodeIndex > -1) {
                    this.m_collectEffectNodes.splice(nodeIndex, 1);
                }

                // 從 tween 陣列中移除
                if (tweenInstance) {
                    const tweenIndex = this.m_currentTweens.indexOf(tweenInstance);
                    if (tweenIndex > -1) {
                        this.m_currentTweens.splice(tweenIndex, 1);
                    }
                }

                // 如果所有動畫都完成了，移除旋轉監聽
                if (this.m_currentTweens.length === 0) {
                }

                // 執行完成回調
                onComplete?.();
            }
        );

        // 如果 tween 建立成功，加入追蹤陣列並啟動
        if (tweenInstance) {
            this.m_currentTweens.push(tweenInstance);
            tweenInstance.start();
        } else {
            // tween 建立失敗，直接執行回調
            log("MagicPot: 建立 Bezier tween 失敗");
            onComplete?.();
        }
    }

    /**
     * @ch 播放魔法罐動畫
     * @param config 動畫配置
     * @returns
     */
    private PlayMagicPotAnimation(config: MagicPotAnim) : Promise<void> {
        return this.PlaySpineAnimation(config.trackIdx, config.name, config.loop);
    }

    /**
     * @ch 並行播放多個魔法罐動畫
     * @param configs 動畫配置陣列
     * @returns
     */
    private async PlayMagicPotAnimations(configs: MagicPotAnim[]): Promise<void> {
        if (!configs || configs.length === 0) {
            return;
        }

        // 並行播放所有動畫
        const promises = configs.map(config =>
            this.PlaySpineAnimation(config.trackIdx, config.name, config.loop)
        );

        await Promise.all(promises);
    }

    /**
     * @ch 播放魔法罐動畫
     * @param trackIdx 軌道索引
     * @param animName 動畫名稱
     * @param isLoop 是否循環
     * @param needRest 是否需要重置
     */
    private async PlaySpineAnimation(trackIdx: number, animName: string, isLoop: boolean = false, needRest: boolean = false): Promise<void> {
        // 若同一 track 已在播相同的循環動畫，跳過以避免重置造成停頓
        if (isLoop) {
            const current = this.ActiveSpine.getCurrent(trackIdx);
            if (current?.animation?.name === animName) {
                return;
            }
        }
        await SpineKit.PlayAnimation(this.ActiveSpine, animName, isLoop, trackIdx, null, needRest);
    }

    /**
     * @ch 根據等級播放待機動畫 (Idle + LV?)
     * @param level 目標等級 client 端 (0-based: 0=LV1, 1=LV2, 2=LV3, 3=LVBingo)
     */
    private PlayLevelAnimations(level: number): void {
        // 錯誤處理：檢查 level 是否在有效範圍內
        if (level < 0) {
            log(`[MagicPotController] PlayLevelAnimations: level ${level} 小於 0，已調整為 0`);
            level = 0;
        }

        // 魔法罐最多支援 4 個等級 (0=LV1, 1=LV2, 2=LV3, 3=LVBingo)
        if (level > MagicPotController.BINGO_LEVEL) {
            log(`[MagicPotController] PlayLevelAnimations: level ${level} 超出最大等級 ${MagicPotController.BINGO_LEVEL}，已調整為 ${MagicPotController.BINGO_LEVEL}`);
            level = MagicPotController.BINGO_LEVEL;
        }

        // 播放待機動畫組合：Idle + LV?
        const animConfigs = MAGIC_POT_ANIMATION.IDLE_ANIM(level);
        this.StopTracksNotIn(animConfigs);
        this.PlayMagicPotAnimations(animConfigs);
    }

    /**
     * @ch 停止魔法罐動畫
     * @param config 動畫配置
     */
    private StopMagicPotAnimation(config: MagicPotAnim): void {
        this.StopSpineAnimation(config.trackIdx);
    }

    /**
     * @ch 停止魔法罐動畫
     * @param trackIdx 軌道索引
     */
    private StopSpineAnimation(trackIdx: number): void {
        this.ActiveSpine.clearTrack(trackIdx);
        this.ActiveSpine.setToSetupPose();
    }

    /**
     * @ch 清除新組合不包含的 track，保留已在播的 track（如 Idle），避免 setToSetupPose 造成畫面頓感
     */
    private StopTracksNotIn(configs: MagicPotAnim[]): void {
        // @ch 建立 trackIdx -> name 的映射，同時比對 track 和動畫名稱才保留
        const keepMap = new Map(configs.map(c => [c.trackIdx, c.name]));
        const maxTrackIdx = LV_START_TRACK_IDX + MagicPotController.BINGO_LEVEL;
        for (let i = 0; i < maxTrackIdx + 1; i++) {
            const currentEntry = this.ActiveSpine.getCurrent(i);
            const currentName = currentEntry?.animation?.name;
            const keepName = keepMap.get(i);
            if (keepName === undefined || currentName !== keepName) {
                this.ActiveSpine.clearTrack(i);
            }
        }
    }

    /**
     * @ch 停止所有魔法罐動畫
     */
    private StopAllSpineAnimations(): void {
        const maxTrackIdx = LV_START_TRACK_IDX + MagicPotController.BINGO_LEVEL;
        for (let i = 0; i < maxTrackIdx + 1; i++) {
            this.ActiveSpine.clearTrack(i);
        }
        this.ActiveSpine.setToSetupPose();
    }

    /**
     * @ch 切換UI
     * @param isFreeGame 是否free game (true=進入FG, false=回到普通模式)
     * @param callback 完成回調
     * @returns
     */
    private async SwitchUI(isFreeGame: boolean, callback?: () => void): Promise<void> {
        try {
            this.StopAllSpineAnimations();
            this.SetFreeSpinTextNodesShow(isFreeGame);
            if (isFreeGame) {
                // 播放 FG_IDLE
                await this.PlayMagicPotAnimations(MAGIC_POT_ANIMATION.FG_IDLE);
            }
            else {
                // 回到普通模式：播放 BottleFloat
                // 注意：m_level 已是 client level，必須走 SetClientLevelInternal 避免 client→client 二次轉換
                this.StopAllSpineAnimations();
                this.SetClientLevelInternal(this.m_level, true);
            }
        } catch (error) {
            log('[MagicPotController] SwitchUI error:', error);
        } finally {
            // 不論成功/失敗，都要執行回調，確保流程不會卡住
            this.InvokeSafeCallback(callback, "SwitchUI");
        }
    }

    /**
     * @ch 播放進入free game動畫
     * @param callback 完成回調
     * @returns
     */
    private async PlayToFreeGame(callback?: () => void): Promise<void> {
        try {
            this.StopAllSpineAnimations();
            await this.PlayMagicPotAnimation(MAGIC_POT_ANIMATION.BINGO_TO_FG);
        } catch (error) {
            log('[MagicPotController] PlayToFreeGame error:', error);
        } finally {
            this.InvokeSafeCallback(callback, "PlayToFreeGame");
        }
    }

    /**
     * @ch 獲取免費遊戲回合數字節點
     * @returns 免費遊戲回合數字節點
     */
    private GetFreeGameRoundNumberNode(): Node {
        if (this.m_freeGameRoundNumberNode) {
            return this.m_freeGameRoundNumberNode;
        }
        eventManager.Dispatch(FREE_GAME_ROUND_UI_EVENT.GET_ROUND_NUMBER_NODE, (node: Node) => {
            if (node) {
                this.m_freeGameRoundNumberNode = node;
            }
        });
        return this.m_freeGameRoundNumberNode;
    }

    /**
     * @ch 把回合數字節點推入對應方向的 RootNode
     */
    private PushToFreeGameNumberRootNode(): void {
        const node = this.GetFreeGameRoundNumberNode();
        if (!node) {
            log('[MagicPotController] PushToFreeGameNumberRootNode: 回合數字節點不存在');
            return;
        }
        const rootNode = this.m_isLandscape
            ? this.m_freeGameNumberRootNodes[0]
            : this.m_freeGameNumberRootNodes[1];
        if (!rootNode) {
            log('[MagicPotController] PushToFreeGameNumberRootNode: RootNode 不存在');
            return;
        }
        this.m_freeGameRoundNumberPopupData = Common.PushNode(node, rootNode);
    }

    /**
     * @ch 把回合數字節點從 RootNode 放回原位
     */
    private PopToFreeGameNumberRootNode(): void {
        if (!this.m_freeGameRoundNumberPopupData) {
            log('[MagicPotController] PopToFreeGameNumberRootNode: 節點尚未推入，略過');
            return;
        }
        Common.PopNode(this.m_freeGameRoundNumberPopupData);
        this.m_freeGameRoundNumberPopupData = null;
    }

    /**
     * @ch 設置免費遊戲Spin文字節點顯示 (true: 顯示, false: 隱藏)
     * @param isShow 是否顯示
     */
    private SetFreeSpinTextNodesShow(isShow: boolean): void {
        if (!this.m_freeSpinTextNodes || this.m_freeSpinTextNodes.length === 0) {
            log('[MagicPotController] SetFreeSpinTextNodesShow: 免費遊戲Spin文字節點不存在');
            return;
        }
        this.m_freeSpinTextNodes.forEach(node => {
            if (node && node.isValid) {
                node.active = isShow;
            }
        });
    }
    //#endregion Methods

    //#region 測試功能
    /**
     * @ch 註冊測試按鍵
     */
    private RegisterTestKeyCodes() {
        if (!DEBUG) return;
        input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 取消註冊測試按鍵
     */
    private UnregisterTestKeyCodes() {
        if (!DEBUG) return;
        input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 檢查測試按鍵
     */
    private CheckTestKeyCode(event: EventKeyboard) {
        return;
        log("CheckTestKeyCode", event.keyCode);
        switch (event.keyCode) {
            case KeyCode.DIGIT_0:
                this.StopAllSpineAnimations();
                this.SetLevel(0);
                break;

            case KeyCode.DIGIT_9:
                this.StopAllSpineAnimations();
                const newLevel = (this.m_level + 1) % (MagicPotController.BINGO_LEVEL + 1);
                this.SetLevel(newLevel);
                break;

            case KeyCode.DIGIT_1:
                // 測試：升級到下一階
                if (this.m_level < 6) {
                    const upgradeData: IEnergyLevelUpgradeInfo = {
                        Upgrade: true,
                        EnergyLevel: this.m_level + 1
                    };
                    eventManager.Dispatch(MAGIC_POT_EVENT.PLAY_UPGRADE_EFFECT, upgradeData, () => {
                        log("[Test] 升級效果播放完成");
                    });
                }
                break;

            case KeyCode.DIGIT_2:
                // 測試：升級到 Bingo
                if (this.m_level < 6) {
                    const upgradeData: IEnergyLevelUpgradeInfo = {
                        Upgrade: true,
                        EnergyLevel: 6
                    };
                    eventManager.Dispatch(MAGIC_POT_EVENT.PLAY_UPGRADE_EFFECT, upgradeData, () => {
                        log("[Test] 升級到 Bingo 完成");
                    });
                }
                break;

            case KeyCode.DIGIT_3:
                // 測試：播放收集效果
                const testPositions = [0, 1, 2]; // 測試位置
                const testData: IEnergyLevelUpgradeInfo[] = [
                    { Upgrade: true, EnergyLevel: this.m_level + 1 }
                ];
                eventManager.Dispatch(MAGIC_POT_EVENT.PLAY_COLLECT_EFFECT, testPositions, testData, () => {
                    log("[Test] 收集效果播放完成");
                }, true);
                break;

            case KeyCode.DIGIT_4:
                // 測試：進入 FG
                eventManager.Dispatch(MAGIC_POT_EVENT.SWITCH_UI, true, () => {
                    log("[Test] 進入 FG 動畫完成");
                });
                break;

            case KeyCode.DIGIT_5:
                // 測試：回到普通模式
                eventManager.Dispatch(MAGIC_POT_EVENT.SWITCH_UI, false, () => {
                    log("[Test] 回到普通模式完成");
                });
                break;
        }
    }
    //#endregion 測試功能
}

