const scatterNode = this.m_gameView.EffectPlate.CreateEffectNode_NodePool(
    col,
    row,
    Game_Define.LAYERS.TWO,
    Game_Define.Symbol.Scatter
);

const scatterSpine = scatterNode?.getComponent( SymbolSpine );
if ( scatterSpine )
{
    // 判斷是否為最後一顆 Scatter，決定用假資料還是真資料
    const isLastScatter = scatterCount >= this.m_totalScatterCount;

    const encodedPos = Common.EncodeServerPosByRowConfig( col, row );

    let collectScatterData: IEnergyLevelUpgradeInfo[];
    if ( isLastScatter )
    {
        const scAccuUpgrade = this.m_gameView.RoundInfo.ScAccuUpgrade;
        collectScatterData = scAccuUpgrade ? [ { Upgrade: scAccuUpgrade.Upgrade ?? false, EnergyLevel: scAccuUpgrade.Stage ?? 0 } ] : [];
    }
    else
    {
        let currentLevel = 0;
        eventManager.Dispatch( MAGIC_POT_EVENT.GET_LEVEL, ( level: number ) => { currentLevel = level; } );
        collectScatterData = [ { Upgrade: false, EnergyLevel: currentLevel } ];
    }

    this.m_pendingEntryEffectCount++;
    void scatterSpine
        .PlayAnimation( "In", scatterSpine.Spine, false, 1 )
        .then( async () =>
        {
            await scatterSpine.PlayAnimation(
                Game_Define.SymbolCollectName,
                scatterSpine.Spine,
                false,
                1,
                ( eventName: string ) =>
                {
                    if ( eventName === "Trail" )
                    {
                        // col 1-3 的第 ≥2 顆 Scatter 靜音 MagicPotCollect（col 0/4/5 與第 1 顆永遠播）
                        const suppressCollectSfx = scatterCount >= 2 && col >= 1 && col <= 3;

